161: func addAllocatableThresholds(thresholds []evictionapi.Threshold) []evictionapi.Threshold {
162: 	additionalThresholds := []evictionapi.Threshold{}
163: 	for _, threshold := range thresholds {
164: 		if threshold.Signal == evictionapi.SignalMemoryAvailable && isHardEvictionThreshold(threshold) {
165: 			// Copy the SignalMemoryAvailable to SignalAllocatableMemoryAvailable
166: 			additionalThresholds = append(additionalThresholds, evictionapi.Threshold{
167: 				Signal:     evictionapi.SignalAllocatableMemoryAvailable,
168: 				Operator:   threshold.Operator,
169: 				Value:      threshold.Value,
170: 				MinReclaim: threshold.MinReclaim,
171: 			})
172: 		}
173: 	}
174: 	return append(append([]evictionapi.Threshold{}, thresholds...), additionalThresholds...)
175: }
