1050: // nodeConditionsLastObservedAt merges the input with the previous observation to determine when a condition was most recently met.
1051: func nodeConditionsLastObservedAt(nodeConditions []v1.NodeConditionType, lastObservedAt nodeConditionsObservedAt, now time.Time) nodeConditionsObservedAt {
1052: 	results := nodeConditionsObservedAt{}
1053: 	// the input conditions were observed "now"
1054: 	for i := range nodeConditions {
1055: 		results[nodeConditions[i]] = now
1056: 	}
1057: 	// the conditions that were not observed now are merged in with their old time
1058: 	for key, value := range lastObservedAt {
1059: 		_, found := results[key]
1060: 		if !found {
1061: 			results[key] = value
1062: 		}
1063: 	}
1064: 	return results
1065: }
