1067: // nodeConditionsObservedSince returns the set of conditions that have been observed within the specified period
1068: func nodeConditionsObservedSince(observedAt nodeConditionsObservedAt, period time.Duration, now time.Time) []v1.NodeConditionType {
1069: 	results := []v1.NodeConditionType{}
1070: 	for nodeCondition, at := range observedAt {
1071: 		duration := now.Sub(at)
1072: 		if duration < period {
1073: 			results = append(results, nodeCondition)
1074: 		}
1075: 	}
1076: 	return results
1077: }
